import { readFileSync } from 'node:fs';
const s=readFileSync('packages/agent-core/src/agent/compaction/strategy.ts','utf8');
const fails=[];
if (!s.includes('DEFAULT_COMPACTION_TRIGGER_RATIO = 0.80')) fails.push('soft80');
if (!s.includes('DEFAULT_COMPACTION_BLOCK_RATIO = 0.92')) fails.push('hard92');
if (!s.includes('DEFAULT_ASYNC_COMPACTION_TRIGGER_RATIO = 0.70')) fails.push('async70');
if (!s.includes('assertCompactionLadderSafety')) fails.push('safety');
if (!s.includes('reservedContextSize: 50_000')) fails.push('reserved50k');
if (!s.includes('absoluteTriggerTokens: 200_000')) fails.push('abs200k');
if (!s.includes('maxRecentMessages: 4')) fails.push('maxRecent4');
if (s.includes('DEFAULT_COMPACTION_TRIGGER_RATIO = 0.08')) fails.push('densify-soft');
